## 🚀 Plano de Implementação por Prioridade

### 🔴 FASE 1: Desacoplar Renderização da Lógica (Crítico)

#### 1.1 Criar `src/core/events.js` - Sistema de Eventos
```javascript
// src/core/events.js
export const EVENT_TYPES = {
  COMBAT_DAMAGE: 'combat:damage',
  COMBAT_MISS: 'combat:miss',
  SPELL_CAST: 'spell:cast',
  PLAYER_MOVE: 'player:move',
  MONSTER_DEATH: 'monster:death',
  MAP_TRANSITION: 'map:transition',
  PROGRESSION_LEVEL_UP: 'progression:levelUp',
};

export class EventDispatcher {
  constructor() {
    this.listeners = new Map();
  }

  subscribe(eventType, callback) {
    if (!this.listeners.has(eventType)) {
      this.listeners.set(eventType, new Set());
    }
    this.listeners.get(eventType).add(callback);
    return () => this.listeners.get(eventType)?.delete(callback);
  }

  emit(eventType, payload) {
    const callbacks = this.listeners.get(eventType) ?? new Set();
    for (const cb of callbacks) {
      try { cb(payload); } catch (e) { console.error(e); }
    }
  }
}

export const worldEvents = new EventDispatcher();
```

#### 1.2 Refatorar `combatEngine.js` para emitir eventos, não UI
```javascript
// ✅ NOVO: combatEngine.js emite eventos, não desenha
