    attackerId: attacker.id,
    defenderId: defender.id,
    damage,
    isCritical: options.isCritical ?? false,
    timestamp: Date.now(),
    // Dados mínimos necessários - cliente enriquece com UI
  });

  return { damageApplied: damage, defenderHp: newHp };
}

// Remove: emitHpDeltaText, pushFloatingText, etc.
// Esses métodos migram para: src/clients/shared/ui/combatText.js
```

#### 1.3 Criar `src/clients/shared/ui/combatText.js`
```javascript
// src/clients/shared/ui/combatText.js
import { worldEvents, EVENT_TYPES } from '../../core/events.js';
import { TILE_SIZE } from '../../core/config.js';

export function initCombatTextUI(canvasContext, floatingTextsArray) {
  worldEvents.subscribe(EVENT_TYPES.COMBAT_DAMAGE, (payload) => {
