#### 2.2 Criar `src/gameplay/fieldSystem.js` - Gerenciador de Campos
```javascript
// src/gameplay/fieldSystem.js
import { worldEvents, EVENT_TYPES } from '../core/events.js';
import { getMonsters, applyMonstersLocal } from '../core/worldStore.js';
import { calculateNewHp } from './combatLogic.js';

const activeFields = new Map(); // Fields ativos com seus ticks

export function createField(fieldData, caster, position) {
  const fieldId = `field_${Date.now()}_${Math.random().toString(36).slice(2, 8)}`;

  const field = {
    id: fieldId,
    ...fieldData,
    casterId: caster.id,
    x: position.x,
    y: position.y,
    z: position.z ?? 7,
    createdAt: Date.now(),
    expiresAt: Date.now() + fieldData.fieldData.duration,
    lastTick: Date.now(),
  };

  // Salva no Firebase via db.js
  await dbSet(`world_fields/${fieldId}`, field);

  // Agenda ticks de dano
  scheduleFieldTicks(fieldId, field);

  worldEvents.emit(EVENT_TYPES.FIELD_CREATED, { field });
  return field;
}

function scheduleFieldTicks(fieldId, field) {
  const interval = field.fieldData.tickDamage?.interval ?? 1000;

  const tickInterval = setInterval(() => {
    if (Date.now() > field.expiresAt) {
      clearInterval(tickInterval);
      removeField(fieldId);
      return;
    }

    // Aplica dano a quem estiver no campo
    applyFieldDamage(field);
  }, interval);

  // Cleanup automático
  setTimeout(() => {
    clearInterval(tickInterval);
    removeField(fieldId);
  }, field.fieldData.duration);
}

function applyFieldDamage(field) {
  const monsters = getMonsters();
  const { tickDamage } = field.fieldData;

  for (const [id, monster] of Object.entries(monsters)) {
    if (monster.dead) continue;
    if (monster.z !== field.z) continue;

    // Verifica se monstro está dentro do campo (1 tile)
    if (Math.abs(monster.x - field.x) <= 0.5 && 
        Math.abs(monster.y - field.y) <= 0.5) {

      const variance = 1 - tickDamage.variance + Math.random() * tickDamage.variance * 2;
      const damage = Math.round(tickDamage.base * variance);
      const newHp = calculateNewHp(monster.stats.hp, -damage, monster.stats.maxHp);

      // Atualiza HP
      applyMonstersLocal(id, { stats: { ...monster.stats, hp: newHp } });
      await dbSet(`world_entities/${id}/stats/hp`, newHp);

      worldEvents.emit(EVENT_TYPES.COMBAT_DAMAGE, {
        attackerId: field.casterId,
        defenderId: id,
        damage,
        damageType: tickDamage.damageType,
        isFieldDamage: true,
      });

      if (newHp <= 0 && !monster.dead) {
        handleMonsterDeath(id, monster);
      }
    }
  }
}

export function removeField(fieldId) {
  activeFields.delete(fieldId);
  dbRemove(`world_fields/${fieldId}`);
  worldEvents.emit(EVENT_TYPES.FIELD_REMOVED, { fieldId });
}
```

