 * Ignora mensagens com ts > CHAT_TTL_MS (expiradas).
 */
export function watchChat(cb) {
  return dbWatchChildren(PATHS.chat, {
    onAdd: (id, data) => {
      if (!data) return;
      const age = Date.now() - (data.ts ?? 0);
      if (age > CHAT_TTL_MS) return; // ignora mensagens antigas
