  } else {
    emitMissText(target);
    const fxId = `miss_player_${playerId}_${targetId}_${now}`;
    const missFx = buildCombatEffectPayload("attackMiss", {
      id: fxId,
      x: target.x,
      y: target.y,
      z: target.z ?? 7,
      now,
    });
    if (missFx) await syncEffect(fxId, missFx);
    pushLog("damage", `${player.name} errou ${target.name ?? targetId} [MISS]`);
