    ctx.fillStyle = "black";
    ctx.fillRect(barX - 1, barY - 1, 28, 5);
    ctx.fillStyle =
      percent > 0.6 ? "#00ff00" : percent > 0.3 ? "#ffff00" : "#ff0000";
    ctx.fillRect(barX, barY, Math.round(26 * percent), 3);
  }
  ctx.restore();
}
