};

// Exemplo de magia de campo (Field)
poisonField: {
  id: "poisonField",
  name: "Campo Venenoso",
  type: SPELL_TYPE.FIELD,
  mpCost: 15,
  cooldownMs: 3000,
  minLevel: 2,
  classes: ["druid"],
  fieldData: {
    fieldId: 4, // ID do sprite do campo venenoso
    duration: 8000, // Campo dura 8 segundos
    tickDamage: { base: 5, variance: 0.1, interval: 1000 }, // Dano por tick
    damageType: "poison",
  },
  range: 3, // Alcance para colocar o campo
  effectId: 18, // Efeito visual ao lançar
  description: "Cria um campo venenoso que causa dano periódico.",
