#### 3.1 Criar `src/gameplay/progressionSystem.js`
```javascript
// src/gameplay/progressionSystem.js
import { PLAYER_CLASSES } from '../config/constants.js';
import { worldEvents, EVENT_TYPES } from '../core/events.js';

// Configuração de progressão simplificada
export const PROGRESSION_CONFIG = {
  xpPerLevel: (level) => Math.floor(100 * Math.pow(1.15, level - 1)),
  statPointsPerLevel: 3,
  maxLevel: 50,

  // Como distribuir pontos por classe
  classStatGrowth: {
    cavaleiro: { hp: 8, atk: 2, def: 1.5, mp: 1 },
    mago: { hp: 3, atk: 1, def: 0.5, mp: 6 },
    arqueiro: { hp: 4, atk: 2.5, def: 0.8, agi: 2 },
    druid: { hp: 5, atk: 1, def: 1, mp: 4, agi: 1 },
    clerigo: { hp: 5, atk: 1, def: 1, mp: 4, agi: 1 },
  },
};

export function calculateXpToNextLevel(currentLevel) {
  return PROGRESSION_CONFIG.xpPerLevel(currentLevel);
}

export function processXpGain(playerId, xpAmount) {
  const player = getPlayer(playerId); // Via worldStore
  if (!player) return;

  let newXp = (player.stats?.xp ?? 0) + xpAmount;
  let newLevel = player.stats?.level ?? 1;
  let statPointsGained = 0;

  // Verifica level up
  while (newXp >= calculateXpToNextLevel(newLevel) && newLevel < PROGRESSION_CONFIG.maxLevel) {
    newXp -= calculateXpToNextLevel(newLevel);
    newLevel++;
    statPointsGained += PROGRESSION_CONFIG.statPointsPerLevel;
  }

  // Aplica mudanças
  const updates = {
    [`online_players/${playerId}/stats/xp`]: newXp,
    [`online_players/${playerId}/stats/level`]: newLevel,
  };

  if (statPointsGained > 0) {
    updates[`online_players/${playerId}/stats/availableStatPoints`] = 
      (player.stats?.availableStatPoints ?? 0) + statPointsGained;
  }

  await batchWrite(updates);

  if (newLevel > (player.stats?.level ?? 1)) {
    worldEvents.emit(EVENT_TYPES.PROGRESSION_LEVEL_UP, {
      playerId,
      newLevel,
      statPointsGained,
    });
  }

  return { levelUp: newLevel > player.stats?.level, newLevel, newXp };
}

export function allocateStatPoint(playerId, statName, amount = 1) {
  const player = getPlayer(playerId);
  const available = player.stats?.availableStatPoints ?? 0;

  if (available < amount) {
    return { success: false, reason: "Pontos insuficientes" };
  }

  const currentStat = player.stats?.[statName] ?? 0;
  const classConfig = PROGRESSION_CONFIG.classStatGrowth[player.class];
  const growthFactor = classConfig?.[statName] ?? 1;

  // Aplica crescimento com fator da classe
  const newValue = currentStat + (amount * growthFactor);

  await batchWrite({
    [`online_players/${playerId}/stats/${statName}`]: newValue,
    [`online_players/${playerId}/stats/availableStatPoints`]: available - amount,
  });

  worldEvents.emit(EVENT_TYPES.PROGRESSION_STAT_ALLOCATED, {
    playerId,
    statName,
    newValue,
    pointsSpent: amount,
  });

  return { success: true, newValue };
}
