// src/gameplay/mapSystem.js
import { worldEvents, EVENT_TYPES } from '../core/events.js';
import { getTileData } from '../core/worldStore.js'; // Função para ler tile do mapa

export function checkTileTransition(player, newX, newY, newZ) {
  const tile = getTileData(newX, newY, newZ);
  if (!tile?.transitions?.length) return null;

  for (const transition of tile.transitions) {
    if (transition.triggerType === 'walk') {
      // Transição automática ao pisar
      return executeTransition(player, transition);
    }
    // Outros tipos: 'use' (clicar), 'npc' (falar com NPC)
  }
  return null;
}

export async function executeTransition(player, transition) {
  const updates = {};
  const playerId = player.id;

  // Atualiza posição do jogador
  updates[`online_players/${playerId}/x`] = transition.targetX ?? player.x;
  updates[`online_players/${playerId}/y`] = transition.targetY ?? player.y;
  updates[`online_players/${playerId}/z`] = transition.targetZ;

  if (transition.targetMap) {
    updates[`online_players/${playerId}/map`] = transition.targetMap;
  }

  await batchWrite(updates);

  worldEvents.emit(EVENT_TYPES.MAP_TRANSITION, {
    playerId,
    from: { x: player.x, y: player.y, z: player.z },
    to: { 
      x: transition.targetX ?? player.x, 
      y: transition.targetY ?? player.y, 
      z: transition.targetZ,
      map: transition.targetMap,
    },
  });

  return { success: true, newPosition: { ...updates } };
}

// Hook para o movement system chamar
export function onPlayerMove(playerId, newX, newY, newZ) {
  const player = getPlayer(playerId);
  if (!player) return;

  const transition = checkTileTransition(player, newX, newY, newZ);
  if (transition) {
    return transition; // Já executou a transição
  }

  // Movimento normal
  return { success: true };
}
```

#### 4.3 Integração com o editor de mapa (Remere's Map Editor)
```javascript
// src/core/mapImporter.js - Exemplo de como ler transições do .otbm
export function parseTileTransitions(otbmTileData) {
  const transitions = [];

  // Procura por items com actionid específico (convenção do editor)
  for (const item of otbmTileData.items ?? []) {
    if (item.actionid >= 1000 && item.actionid < 2000) {
      // ActionID 1000-1999 reservados para transições
      const transitionData = decodeTransitionActionId(item.actionid);
      if (transitionData) {
        transitions.push({
          triggerType: 'walk',
          targetZ: transitionData.z,
          targetX: transitionData.x,
          targetY: transitionData.y,
          itemId: item.id,
          description: `Ir para andar ${transitionData.z}`,
        });
      }
    }
  }

  return transitions;
}

function decodeTransitionActionId(actionId) {
  // Exemplo: actionid 1XYZ onde XYZ = coordenada compactada
  // Isso é uma convenção que você define para o editor
  const z = Math.floor((actionId % 1000) / 100);
  const x = Math.floor((actionId % 100) / 10);
  const y = actionId % 10;
  return { z, x, y };
}
