// worldStore.js — mmoRPGGame  [FASE IMEDIATA — refatorado]
// Estado global do mundo — fonte única de verdade.
// Usado por: worldEngine.html, rpg.html, admin.html
//
// MUDANÇA: import { dbWatch } from './firebaseClient.js'
