function toStringSafe(value, fallback = "") {
  if (value === undefined || value === null) return fallback;
  return String(value);
}

function normalizeOutfitPack(pack, fallback) {
  const raw = toStringSafe(pack, fallback);
  if (!raw) return fallback;
  const aliases = {
